		int pageSize = bWordVO.getPageSize() > 0 ? bWordVO.getPageSize() : 10;

		int startRowNum = (nowPage - 1) * pageSize + 1;
		int endRowNum = nowPage * pageSize;

		bWordVO.setStartRowNum(startRowNum);
