		bWordVO.setNewPage(nowPage);
		bWordVO.setPageSize(pageSize);

		List<BWordVO> resultData = bWordMngService.selectBWordList(bWordVO);

		if(!resultData.isEmpty()){
			mv.addObject("maxPage", resultData.get(0).getTotCnt());
