		List<BWordVO> resultData = bWordMngService.usageBWordList(bWordVO);
		mv.addObject("resultList", resultData);
		return success();
	}

	@RequestMapping("/bword/getBWordCacheEntries.json")
	public ModelAndView getBWordCacheEntries() throws Exception {
		List<Map<String, Object>> cacheEntries = new ArrayList<Map<String, Object>>();

		if (cacheManager instanceof EhCacheCacheManager) {
			EhCacheCacheManager ehCacheCacheManager = (EhCacheCacheManager) cacheManager;
			net.sf.ehcache.Cache cache = ehCacheCacheManager.getCacheManager().getCache("bwordCache");

			if (cache != null) {
				List keys = cache.getKeys();

				for (Object key : keys) {
					Element element = cache.get(key);
					if (element == null) {

						continue;
					}

					Map<String, Object> entry = new HashMap<String, Object>();
					entry.put("key", key);
					entry.put("value", element.getObjectValue());
					entry.put("hitCount", element.getHitCount());
					entry.put("creationTime", element.getCreationTime());
					entry.put("lastAccessTime", element.getLastAccessTime());
					cacheEntries.add(entry);
				}
			}
		}

		mv.addObject("cacheSize", cacheEntries.size());
		mv.addObject("cacheEntries", cacheEntries);
		return success();
	}

}

