<script type="text/javascript">
    let datagrid;
    let grid_data = [];
    let maxPage, nowPage, pageSize;

    $(document).ready(function() {
        // from/to 날짜 최대값: 오늘 기준 3일 전 (그 이후 날짜는 선택 불가)
        const maxDate = new Date();
        maxDate.setDate(maxDate.getDate() - 3);
        const maxDateStr = maxDate.toISOString().split('T')[0];
        document.getElementById("cFrmDate").max = maxDateStr;
        document.getElementById("cToDate").max = maxDateStr;

        // 직접 입력 또는 달력 선택 시 max 초과 차단
        $("#cFrmDate, #cToDate").on("change", function() {
            if ($(this).val() > maxDateStr) {
                alert("파일 복원은 오늘 기준 3일 이상 지난 신고일만 선택 가능합니다.");
                $(this).val(maxDateStr);
            }
        });

        // 초기 데이터 로드
        ajaxData(1);

        // 조회 버튼 이벤트
        $("#searchBtn").click(function() { ajaxData(1); });

        // 엔터키 조회
        $("#sttemntNoSrchBody").keydown(function(e) { if(e.keyCode == 13) ajaxData(1); });

        // 일괄 복원 버튼 이벤트
        $("#bulkRestoreBtn").click(function() {
            bulkRestore();
        });

        // 전체 복원 버튼 이벤트
        $("#allRestoreBtn").click(function() {
            allRestore();
        });
    });

    const __createElements = () => {
        let size = "width:100%; height:651px;";
        let heightSize = "height:" + ((30 * grid_data.length) + 51) + "px;";
        if(grid_data.length < 20) size = "width:100%;" + heightSize;

        if (SBGrid.getGrid('datagrid')) datagrid.destroy();

        let GridInitInfo = {
            "strParentId"           : "sbGridArea"
            , "strId"               : "datagrid"
            , "strCaption"          : "순번^선택^신고번호^제목^신고일^전체 파일"
            , "strColWidth"         : "5%,5%,13%,52%,17%,8%"
            , "strJsonRef"          : "grid_data"
            , "strStyle"            : size
            , "strDataHeight"       : "30"
            , "strToolTip"          : "true"
            , "bAllowUserResize"    : true
            , "strSelectMode"       : "free"
            , "strEmptyRecords"     : "검색결과가 없습니다."
            , "strOverflow"         : "hidden"
            , "strExplorerbar"      : "vertical"
            , "bIsFitWidth"         : true
        };
        let SBGridColumnInitInfo = [
            { "id" : "col0" , "type" : "output"   , "ref" : "rowNum"      , "style" : "text-align:center" }
            , { "id" : "col1" , "type" : "checkbox" , "ref" : "check"       , "style" : "text-align:center" }
            , { "id" : "col2" , "type" : "output"   , "ref" : "sttemntNo"   , "style" : "text-align:center" }
            , { "id" : "col3" , "type" : "output"   , "ref" : "cATitle"     , "style" : "text-align:left" }
            , { "id" : "col4" , "type" : "output"   , "ref" : "cDate"       , "style" : "text-align:center" }
            , { "id" : "col5" , "type" : "output"   , "ref" : "fileCnt"     , "style" : "text-align:center" }
            , { "id" : "col6" , "type" : "output"   , "ref" : "cNo"         , "bIsColHidden" : true }
        ];
        datagrid = createSBDataGrid(GridInitInfo);
        datagrid.createColumns(SBGridColumnInitInfo);
        datagrid.addEventListener("onclick", "fnRowClick", "", "");
    }

    const ajaxData = (newPage) => {
        let data = {
            "newPage": newPage,
            "cFrmDate": $("#cFrmDate").val(),
            "cToDate": $("#cToDate").val(),
            "sttemntNo": $("#sttemntNoSrchHead").val() + "-" + $("#sttemntNoSrchBody").val()
        };
        $.ajax({
            url : "<c:url value='/fileRestore/selectRestoreSingoList.json'/>",
            type : 'post', data : data, dataType : 'json',
            success : function(json) {
                grid_data = json.resultList;
                for(let i=0; i<grid_data.length; i++) {
                    grid_data[i].check = false;
                    grid_data[i].rowNum = (json.newPage - 1) * json.pageSize + i + 1;
                }
                $("#totalCnt").text(json.maxPage);
                $("#totalFileCnt").text(json.totalFileCnt);
                __createElements();
                maxPage = json.maxPage; nowPage = json.newPage; pageSize = json.pageSize;
                $('#shim').smartpaginator({ totalrecords: maxPage, recordsperpage: pageSize, initval: nowPage, onchange: ajaxData });
            }
        });
    }

    function bulkRestore() {
        let selectedSingoNos = [];
        for(let i=1; i<=grid_data.length; i++) {
            if(datagrid.getTextMatrix(i, 1) == "true" || datagrid.getTextMatrix(i, 1) == "1") {
                selectedSingoNos.push(datagrid.getTextMatrix(i, 6));
            }
        }

        if(selectedSingoNos.length === 0) {
            alert("복원할 신고 건을 선택해 주세요.");
            return;
        }

        if(confirm("선택한 " + selectedSingoNos.length + "건에 대해 일괄 복원을 요청하시겠습니까?")) {
            $.ajax({
                url: "<c:url value='/fileRestore/updateBulkFileRestore.do'/>",
                type: 'post',
                data: { singoNos: selectedSingoNos },
                dataType: 'json',
                success: function(res) {
                    alert(res.message);
                    ajaxData(nowPage);
                },
                error: function() {
                    alert("서버 통신 중 오류가 발생했습니다.");
                }
            });
        }
    }

    function allRestore() {
        if(grid_data.length === 0) {
            alert("조회된 결과가 없습니다.");
            return;
        }

        if(confirm("현재 검색 결과 전체(" + maxPage + "건)에 대해 복원을 요청하시겠습니까?\n(데이터 양에 따라 시간이 오래 걸릴 수 있습니다.)")) {
            let data = {
                "cFrmDate": $("#cFrmDate").val(),
                "cToDate": $("#cToDate").val(),
                "sttemntNo": $("#sttemntNoSrchHead").val() + "-" + $("#sttemntNoSrchBody").val()
            };
            $.ajax({
                url: "<c:url value='/fileRestore/updateAllFileRestore.do'/>",
                type: 'post',
                data: data,
                dataType: 'json',
                success: function(res) {
                    alert(res.message);
                    ajaxData(nowPage);
                },
                error: function() {
                    alert("서버 통신 중 오류가 발생했습니다.");
                }
            });
        }
    }

    function sethyphen(obj) {
        let rawVal = obj.value.replace(/-/g, '');
        if (rawVal.length > 4) obj.value = rawVal.slice(0, 4) + '-' + rawVal.slice(4);
        else obj.value = rawVal;
    }

    function fnRowClick() {
        if (datagrid.getMouseRow() === 0 || datagrid.getCol() === 0 || datagrid.getCol() === 1) {
            return false;
        }
        const cNo = datagrid.getTextMatrix(datagrid.getMouseRow(), datagrid.getColRef("cNo"));
        const sttemntNo = datagrid.getTextMatrix(datagrid.getMouseRow(), datagrid.getColRef("sttemntNo"));
        const param = {
            "C_NO" : cNo,
            "STTEMNT_NO" : sttemntNo,
            "TITLE": "신고현황"
        };
        const url = "/sia/vhclTrfcVltnInq/safeSingoMngInqPup.do?menuId="+"<c:out value='${param.menuId}'/>";
        fn_postUrlPopupSingle(url, "1500", "800", param);
    }
</script>
</body>
</html>
